import{_ as a,c as t,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Configuración avanzada: Guía detallada de funciones avanzadas | Antigravity-Manager","description":"Aprende los métodos de configuración avanzada de Antigravity-Manager. Domina funciones avanzadas como programación de cuentas, enrutamiento de modelos, gestión de cuotas y estadísticas de monitoreo.","frontmatter":{"title":"Configuración avanzada: Guía detallada de funciones avanzadas | Antigravity-Manager","order":300,"sidebarTitle":"Actualiza el sistema al nivel de producción","subtitle":"Configuración avanzada: Guía detallada de funciones avanzadas","description":"Aprende los métodos de configuración avanzada de Antigravity-Manager. Domina funciones avanzadas como programación de cuentas, enrutamiento de modelos, gestión de cuotas y estadísticas de monitoreo."},"headers":[],"relativePath":"es/lbjlaq/Antigravity-Manager/advanced/index.md","filePath":"es/lbjlaq/Antigravity-Manager/advanced/index.md"}'),n={name:"es/lbjlaq/Antigravity-Manager/advanced/index.md"};function o(d,e,r,c,l,p){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="configuracion-avanzada" tabindex="-1">Configuración avanzada <a class="header-anchor" href="#configuracion-avanzada" aria-label="Permalink to &quot;Configuración avanzada&quot;">​</a></h1><p>En este capítulo se explican en profundidad las funciones avanzadas de Antigravity Tools: gestión de configuración, políticas de seguridad, programación de cuentas, enrutamiento de modelos, gestión de cuotas, estadísticas de monitoreo y soluciones de despliegue en servidor. Tras dominar estos contenidos, podrás elevar Antigravity Tools de &quot;funcional&quot; a &quot;fácil de usar, estable y operable&quot;.</p><h2 id="contenido-de-este-capitulo" tabindex="-1">Contenido de este capítulo <a class="header-anchor" href="#contenido-de-este-capitulo" aria-label="Permalink to &quot;Contenido de este capítulo&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descripción</th></tr></thead><tbody><tr><td><a href="./config/">Configuración completa</a></td><td>Campos completos de AppConfig/ProxyConfig, ubicación de persistencia y semántica de actualización en caliente</td></tr><tr><td><a href="./security/">Seguridad y privacidad</a></td><td><code>auth_mode</code>, <code>allow_lan_access</code> y diseño de línea base de seguridad</td></tr><tr><td><a href="./scheduling/">Programación de alta disponibilidad</a></td><td>Rotación, cuentas fijas, sesiones pegajosas y mecanismo de reintento en caso de fallo</td></tr><tr><td><a href="./model-router/">Enrutamiento de modelos</a></td><td>Mapeo personalizado, prioridad de comodines y estrategias preestablecidas</td></tr><tr><td><a href="./quota/">Gestión de cuotas</a></td><td>Estrategias combinadas de Quota Protection + Smart Warmup</td></tr><tr><td><a href="./monitoring/">Proxy Monitor</a></td><td>Registros de solicitudes, filtrado, restauración de detalles y exportación</td></tr><tr><td><a href="./token-stats/">Estadísticas de Token</a></td><td>Métricas de estadísticas desde la perspectiva de costos e interpretación de gráficos</td></tr><tr><td><a href="./context-compression/">Estabilidad de sesiones largas</a></td><td>Compresión de contexto, almacenamiento en caché de firmas y compresión de resultados de herramientas</td></tr><tr><td><a href="./system/">Capacidades del sistema</a></td><td>Multiidioma/temas/actualizaciones/inicio automático/HTTP API Server</td></tr><tr><td><a href="./deployment/">Despliegue en servidor</a></td><td>Selección y operaciones de Docker noVNC vs Headless Xvfb</td></tr></tbody></table><h2 id="ruta-de-aprendizaje-recomendada" tabindex="-1">Ruta de aprendizaje recomendada <a class="header-anchor" href="#ruta-de-aprendizaje-recomendada" aria-label="Permalink to &quot;Ruta de aprendizaje recomendada&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Orden recomendado</p><p>Este capítulo es bastante extenso, se recomienda aprender por módulos en el siguiente orden:</p></div><p><strong>Primera fase: Configuración y seguridad (obligatorio)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuración completa → Seguridad y privacidad</span></span>
<span class="line"><span>config      security</span></span></code></pre></div><p>Primero entiende el sistema de configuración (qué requiere reinicio, qué admite actualización en caliente), luego aprende las configuraciones de seguridad (especialmente cuando se exponga a LAN/Internet).</p><p><strong>Segunda fase: Programación y enrutamiento (recomendado)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Programación de alta disponibilidad → Enrutamiento de modelos</span></span>
<span class="line"><span>scheduling    model-router</span></span></code></pre></div><p>Aprende a obtener la máxima estabilidad con el número mínimo de cuentas, luego usa el enrutamiento de modelos para aislar cambios en el proveedor.</p><p><strong>Tercera fase: Cuotas y monitoreo (según necesidad)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Gestión de cuotas → Proxy Monitor → Estadísticas de Token</span></span>
<span class="line"><span>quota        monitoring      token-stats</span></span></code></pre></div><p>Evita el agotamiento silencioso de cuotas, convierte las llamadas de caja negra en sistema observable, optimiza costos mediante cuantificación.</p><p><strong>Cuarta fase: Estabilidad y despliegue (avanzado)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Estabilidad de sesiones largas → Capacidades del sistema → Despliegue en servidor</span></span>
<span class="line"><span>context-compression  system    deployment</span></span></code></pre></div><p>Resuelve problemas latentes en sesiones largas, haz que el cliente sea más como un producto, finalmente aprende el despliegue en servidor.</p><p><strong>Selección rápida</strong>:</p><table tabindex="0"><thead><tr><th>Tu escenario</th><th>Empieza con</th></tr></thead><tbody><tr><td>La rotación de múltiples cuentas es inestable</td><td><a href="./scheduling/">Programación de alta disponibilidad</a></td></tr><tr><td>Quieres fijar un nombre de modelo específico</td><td><a href="./model-router/">Enrutamiento de modelos</a></td></tr><tr><td>Las cuotas siempre se agotan</td><td><a href="./quota/">Gestión de cuotas</a></td></tr><tr><td>Quieres ver registros de solicitudes</td><td><a href="./monitoring/">Proxy Monitor</a></td></tr><tr><td>Quieres estadísticas de consumo de Token</td><td><a href="./token-stats/">Estadísticas de Token</a></td></tr><tr><td>Las conversaciones largas a menudo fallan</td><td><a href="./context-compression/">Estabilidad de sesiones largas</a></td></tr><tr><td>Necesitas exponer a LAN</td><td><a href="./security/">Seguridad y privacidad</a></td></tr><tr><td>Necesitas desplegar en servidor</td><td><a href="./deployment/">Despliegue en servidor</a></td></tr></tbody></table><h2 id="requisitos-previos" tabindex="-1">Requisitos previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos previos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de comenzar, confirma que</p><ul><li>Has completado el capítulo <a href="./../start/">Inicio rápido</a> (al menos completar instalación, agregar cuenta, iniciar proxy inverso)</li><li>Has completado al menos un protocolo en <a href="./../platforms/">Plataformas e integraciones</a> (como OpenAI o Anthropic)</li><li>El proxy inverso local puede responder solicitudes normalmente</li></ul></div><h2 id="siguientes-pasos" tabindex="-1">Siguientes pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes pasos&quot;">​</a></h2><p>Después de completar este capítulo, puedes continuar con:</p><ul><li><a href="./../faq/">Preguntas frecuentes</a>: Guía de solución de problemas cuando encuentres errores como 401/404/429/interrupción en streaming</li><li><a href="./../appendix/">Apéndice</a>: Materiales de referencia como tabla rápida de endpoints, modelos de datos, límites de capacidad de z.ai, etc.</li></ul>`,25)])])}const g=a(n,[["render",o]]);export{m as __pageData,g as default};
